--- src/routes/index.tsx	
+++ src/routes/index.tsx	
@@ -1,1000 +1,1009 @@
 import { component$, $, useStore, useVisibleTask$ } from "@builder.io/qwik";
 import type { DocumentHead } from "@builder.io/qwik-city";
 import { Link } from "@builder.io/qwik-city";
 import { AntiTabulaRasa } from "../components/onboarding/anti-tabula-rasa";
 import { ProjectBriefCard } from "../components/brief/project-brief-card";
 import { BriefRefinery } from "../components/brief/brief-refinery";
 import { AuthPanel } from "../components/auth/auth-panel";
 import { LandingPage } from "../components/landing/landing-page";
 import { FolioMenu } from "../components/folio/folio-menu";
 import type { ProjectBrief, ProjectInterviewAnswers, Folio } from "../types";
 import {
   buildStarterDocument,
   createProjectBrief,
   loadDraftHtml,
   loadProjectBrief,
   plainTextToHtml,
   saveProjectBrief,
 } from "../utils/anti-tabula-rasa";
 import {
   clearIdbStore,
   loadFoliosFromIdb,
   loadActiveFolioIdFromIdb,
   loadFolioContentFromIdb,
   saveFoliosToIdb,
   saveActiveFolioIdToIdb,
   saveFolioContentToIdb,
 } from "../utils/idb";
 import { marked } from "marked";
 import { TwyneEditor } from "../components/editor/twyne-editor";
 import { PersonasPanel } from "../components/personas/personas-panel";
 import { RubricPanel } from "../components/rubric/rubric-panel";
 import { CommentsPanel } from "../components/comments/comments-panel";
 import { CitationsPanel } from "../components/citations/citations-panel";

 type RightPanel = "personas" | "rubric" | "comments" | "citations";

 interface PanelTab {
   id: RightPanel;
   /** Section number on the masthead, e.g. "I" */
   numeral: string;
   /** Departmental name */
   label: string;
   /** Sub-line under the label */
   kicker: string;
   /** CSS color variable for the tab's accent */
   accent: string;
 }

 type AppMode = "landing" | "onboarding" | "refining" | "workspace" | "loading";

 interface LayoutStore {
   rightPanel: RightPanel;
   leftSidebarOpen: boolean;
   rightPanelOpen: boolean;
   hydrated: boolean;
   brief: ProjectBrief | null;
   editorSeed: string;
   authOpen: boolean;
   mode: AppMode;
   folios: Folio[];
   activeFolioId: string | null;
   folioKey: number;
   rightPanelWidth: number;
   // Inline form states (replace native prompts/confirms)
   newFolioFormOpen: boolean;
   confirmNukeOpen: boolean;
 }

 /* ────────────────────────────────────────────────────────────────
  *  Editorial dateline — formatted like a print magazine masthead.
  *  e.g. "Vol. I · No. 117 · Sunday, the 26th of April, 2026"
  * ──────────────────────────────────────────────────────────────── */
 function editorialDateline(now = new Date()): string {
   const days = [
     "Sunday",
     "Monday",
     "Tuesday",
     "Wednesday",
     "Thursday",
     "Friday",
     "Saturday",
   ];
   const months = [
     "January",
     "February",
     "March",
     "April",
     "May",
     "June",
     "July",
     "August",
     "September",
     "October",
     "November",
     "December",
   ];
   const day = now.getDate();
   const ordinal = (n: number) => {
     const s = ["th", "st", "nd", "rd"];
     const v = n % 100;
     return n + (s[(v - 20) % 10] || s[v] || s[0]);
   };
   const start = new Date(now.getFullYear(), 0, 0);
   const diff = (now.getTime() - start.getTime()) / 86400000;
   const dayOfYear = Math.floor(diff);
   return `Vol. I · No. ${dayOfYear} · ${days[now.getDay()]}, the ${ordinal(day)} of ${months[now.getMonth()]}, ${now.getFullYear()}`;
 }

 export default component$(() => {
   const store = useStore<LayoutStore>({
     rightPanel: "personas",
     leftSidebarOpen: false,
     rightPanelOpen: true,
     hydrated: false,
     brief: null,
     editorSeed: "",
     authOpen: false,
     mode: "landing",
     folios: [],
     activeFolioId: null,
     folioKey: 0,
     rightPanelWidth: 340,
     newFolioFormOpen: false,
     confirmNukeOpen: false,
   });

   // eslint-disable-next-line qwik/no-use-visible-task
   useVisibleTask$(({ cleanup }) => {
     (async () => {
       console.log("[twyne:index] useVisibleTask$ START — loading saved state");
       const brief = await loadProjectBrief();
       const folios = await loadFoliosFromIdb();
       const activeFolioId = await loadActiveFolioIdFromIdb();

       // Migration: old storage had a single draft. If we have a brief but no
       // folios, create a Folio I from the legacy draft key.
       if (brief && folios.length === 0) {
         const legacyDraft = await loadDraftHtml();
         const draftFolio: Folio = {
           id: crypto.randomUUID(),
           name: brief.answers.workingTitle || "Current draft",
           type: "draft",
           createdAt: brief.completedAt,
           updatedAt: Date.now(),
         };
         await saveFoliosToIdb([draftFolio]);
         await saveFolioContentToIdb(draftFolio.id, legacyDraft);
         await saveActiveFolioIdToIdb(draftFolio.id);
         store.folios = [draftFolio];
         store.activeFolioId = draftFolio.id;
         store.editorSeed = legacyDraft;
         console.log("[twyne:index] migrated legacy draft → Folio I");
       } else if (folios.length > 0) {
         store.folios = folios;
         store.activeFolioId = activeFolioId ?? folios[0].id;
         const content = await loadFolioContentFromIdb(store.activeFolioId);
         store.editorSeed = content;
         console.log(
           "[twyne:index] loaded folios:",
           folios.length,
           "active:",
           store.activeFolioId,
         );
       }

       store.hydrated = true;
       console.log("[twyne:index] hydrated = true");

       if (store.mode !== "landing") {
         console.log(
           "[twyne:index] SKIPPING storage restore because mode is",
           store.mode,
         );
         return;
       }

       store.brief = brief;
       store.mode = brief ? "workspace" : "landing";
       console.log("[twyne:index] restored from storage → mode:", store.mode);
     })();

     const handler = (e: Event) => {
       console.log("[twyne:index] RECEIVED twyne:submit-interview event");
       const detail = (e as CustomEvent).detail as {
         answers: ProjectInterviewAnswers;
         existingMaterial?: string;
         filename?: string;
       };
       try {
         const brief = createProjectBrief(detail.answers, store.brief);
         const material = detail.existingMaterial?.trim() ?? "";
         let draftHtml: string;
         if (material) {
           const isMarkdown = detail.filename?.match(/\.(md|markdown)$/i);
           const isHtml = material.startsWith("<") && material.includes("</");
           if (isMarkdown) {
             draftHtml = marked.parse(material, { async: false }) as string;
           } else if (isHtml) {
             draftHtml = material;
           } else {
             draftHtml = plainTextToHtml(material);
           }
         } else {
           draftHtml = buildStarterDocument(detail.answers);
         }

         // Create Folio I for the new piece
         const folio: Folio = {
           id: crypto.randomUUID(),
           name: brief.answers.workingTitle || "Current draft",
           type: "draft",
           createdAt: Date.now(),
           updatedAt: Date.now(),
         };

         store.brief = brief;
         store.folios = [folio];
         store.activeFolioId = folio.id;
         store.folioKey += 1;
         store.editorSeed = draftHtml;
         store.mode = "workspace";
         store.leftSidebarOpen = true;

         console.log(
           "[twyne:index] created piece + Folio I → mode:",
           store.mode,
           "brief:",
           brief.answers.workingTitle,
         );
         void saveProjectBrief(brief);
         void saveFoliosToIdb([folio]);
         void saveFolioContentToIdb(folio.id, draftHtml);
         void saveActiveFolioIdToIdb(folio.id);
       } catch (err: any) {
         console.error(
           "[twyne:index] EVENT HANDLER THREW:",
           err?.message ?? err,
         );
       }
     };
     // ── Save editor content to the active folio ──
     const contentHandler = (e: Event) => {
       const html = (e as CustomEvent).detail as string;
       if (store.activeFolioId) {
         void saveFolioContentToIdb(store.activeFolioId, html);
         const idx = store.folios.findIndex((f) => f.id === store.activeFolioId);
         if (idx >= 0) {
           store.folios[idx].updatedAt = Date.now();
           void saveFoliosToIdb(store.folios);
         }
       }
     };
     window.addEventListener("twyne:content", contentHandler);
     cleanup(() => window.removeEventListener("twyne:content", contentHandler));

     // ── Persist layout (width, margin, running header, page numbers) ──
     const layoutHandler = (e: Event) => {
       const next = (e as CustomEvent).detail;
       if (!next || !store.activeFolioId) return;
       const idx = store.folios.findIndex((f) => f.id === store.activeFolioId);
       if (idx < 0) return;
       store.folios[idx] = {
         ...store.folios[idx],
         layout: next,
         updatedAt: Date.now(),
       };
       void saveFoliosToIdb(store.folios);
     };
     window.addEventListener("twyne:layout", layoutHandler);
     cleanup(() => window.removeEventListener("twyne:layout", layoutHandler));

     // ── Persist editable running header / footer text ──
     const headerHandler = (e: Event) => {
       const text = (e as CustomEvent).detail as string;
       if (!store.activeFolioId) return;
       const idx = store.folios.findIndex((f) => f.id === store.activeFolioId);
       if (idx < 0) return;
       store.folios[idx] = {
         ...store.folios[idx],
         header: text,
         updatedAt: Date.now(),
       };
       void saveFoliosToIdb(store.folios);
     };
     const footerHandler = (e: Event) => {
       const text = (e as CustomEvent).detail as string;
       if (!store.activeFolioId) return;
       const idx = store.folios.findIndex((f) => f.id === store.activeFolioId);
       if (idx < 0) return;
       store.folios[idx] = {
         ...store.folios[idx],
         footer: text,
         updatedAt: Date.now(),
       };
       void saveFoliosToIdb(store.folios);
     };
     window.addEventListener("twyne:header", headerHandler);
     window.addEventListener("twyne:footer", footerHandler);
     cleanup(() => window.removeEventListener("twyne:header", headerHandler));
     cleanup(() => window.removeEventListener("twyne:footer", footerHandler));

     window.addEventListener("twyne:submit-interview", handler);
     cleanup(() =>
       window.removeEventListener("twyne:submit-interview", handler),
     );
   });

   const panelTabs: PanelTab[] = [
     {
       id: "personas",
       numeral: "I",
       label: "Cast",
       kicker: "Editors in residence",
       accent: "var(--color-vermilion)",
     },
     {
       id: "rubric",
       numeral: "II",
       label: "Rubric",
       kicker: "Dept. of Rigor",
       accent: "var(--color-cobalt)",
     },
     {
       id: "comments",
       numeral: "III",
       label: "Marginalia",
       kicker: "Notes in the margin",
       accent: "var(--color-mustard)",
     },
     {
       id: "citations",
       numeral: "IV",
       label: "Apparatus",
       kicker: "Sources & sourcerers",
       accent: "var(--color-periwinkle)",
     },
   ];

   if (!store.hydrated) {
     return (
       <div class="flex h-screen items-center justify-center bg-[var(--color-paper)] text-[var(--color-ink-muted)]">
         <div class="folio px-6 py-5 text-center">
           <p class="dept-label">Press Room</p>
           <p
             class="mt-2 font-display text-lg italic text-[var(--color-ink-light)]"
             style="font-family: var(--font-display);"
           >
             Setting the type…
           </p>
         </div>
       </div>
     );
   }

   return (
     <div class="min-h-screen relative">
       {/* ── Visible debug HUD ── */}
       {(() => {
         // Expose a global reset for dev console access
         if (typeof window !== "undefined") {
           (window as any).__twyne_reset__ = async () => {
             await clearIdbStore();
             localStorage.clear();
             sessionStorage.clear();
             window.location.reload();
           };
         }
         return null;
       })()}
       <div
         style={{
           position: "fixed",
           bottom: "12px",
           right: "12px",
           zIndex: 99999,
           background: "#111",
           color: "#0f0",
           fontFamily: "monospace",
           fontSize: "12px",
           padding: "12px",
           borderRadius: "6px",
           maxWidth: "320px",
           lineHeight: 1.5,
           boxShadow: "0 4px 20px rgba(0,0,0,0.5)",
         }}
       >
         <div style={{ color: "#f90", fontWeight: "bold", marginBottom: "4px" }}>
           TWYNE DEBUG
         </div>
         <div>mode: {store.mode}</div>
         <div>folios: {store.folios.length}</div>
         <div>
           active:{" "}
           {store.activeFolioId
             ? (store.folios.find((f) => f.id === store.activeFolioId)?.name ??
               "?")
             : "none"}
         </div>
         <div>brief: {store.brief?.answers.workingTitle ?? "null"}</div>
         <div>seedLen: {store.editorSeed?.length ?? 0}</div>
       </div>

       {store.mode === "landing" && (
         <LandingPage
           onStartBrief$={$(() => {
             store.mode = "onboarding";
           })}
           onSkipToEditor$={$(() => {
             store.mode = "workspace";
             store.leftSidebarOpen = true;
             if (store.folios.length === 0) {
               const folio: Folio = {
                 id: crypto.randomUUID(),
                 name: "Current draft",
                 type: "draft",
                 createdAt: Date.now(),
                 updatedAt: Date.now(),
               };
               store.folios = [folio];
               store.activeFolioId = folio.id;
               store.editorSeed = "";
               void saveFoliosToIdb([folio]);
               void saveActiveFolioIdToIdb(folio.id);
             }
           })}
         />
       )}

       {store.mode === "refining" && (
         <BriefRefinery
           initialAnswers={store.brief?.answers ?? null}
           onSave$={$((answers: ProjectInterviewAnswers) => {
             const brief = createProjectBrief(answers, store.brief);
             store.brief = brief;
             store.mode = "workspace";
             void saveProjectBrief(brief);
           })}
           onCancel$={$(() => {
             store.mode = "workspace";
           })}
         />
       )}

       {store.mode === "onboarding" && (
         <AntiTabulaRasa
           mode="first-run"
           initialAnswers={null}
           onSubmit$={$(() => {
             console.warn(
               "[twyne:index] onSubmit$ prop called — this should NOT happen. The event handler should have fired.",
             );
           })}
           onCancel$={$(() => {
             store.mode = store.brief ? "workspace" : "landing";
           })}
         />
       )}

       {store.mode === "workspace" && (
         <div class="flex h-screen bg-[var(--color-paper)] overflow-hidden">
           {/* ── The Drawer (left sidebar) ──────────────────────── */}
           <aside
             class={`sidebar-transition flex-shrink-0 border-r-2 border-double border-[var(--color-paper-3)] bg-[var(--color-paper-2)] ${
               store.leftSidebarOpen ? "w-72" : "w-0"
             } overflow-hidden`}
           >
             <div class="w-72 h-full flex flex-col">
               <div class="px-5 py-4 border-b border-[var(--color-paper-3)]">
                 <p class="dept-label">Drawer No. III</p>
                 <h2
                   class="mt-1 text-2xl text-[var(--color-ink)]"
                   style="font-family: var(--font-display); font-weight: 600; letter-spacing: -0.01em;"
                 >
                   Pieces in Progress
                 </h2>
               </div>

               <div class="flex-1 overflow-y-auto px-4 py-4 space-y-4">
                 <ProjectBriefCard
                   brief={store.brief}
                   onStartInterview$={$(() => {
                     store.mode = "refining";
                   })}
                 />

                 <div
                   class="ornament-divider"
                   style="font-family: var(--font-display);"
                 >
                   ❦
                 </div>

                 <div class="space-y-1">
                   {store.folios.map((folio, idx) => {
                     const active = store.activeFolioId === folio.id;
                     return (
                       <button
                         key={folio.id}
                         class={`w-full text-left px-3 py-2.5 text-sm focus-ring ${
                           active
                             ? "border border-[var(--color-paper-3)] bg-[var(--color-paper-soft)] font-medium text-[var(--color-ink)]"
                             : "border border-transparent text-[var(--color-ink-light)] hover:bg-[var(--color-paper-soft)]"
                         }`}
                         style="font-family: var(--font-serif); border-radius: 2px;"
                         onClick$={$(async () => {
                           if (active) return;
                           const content = await loadFolioContentFromIdb(
                             folio.id,
                           );
                           store.activeFolioId = folio.id;
                           store.editorSeed = content;
                           store.folioKey += 1;
                           void saveActiveFolioIdToIdb(folio.id);
                           window.dispatchEvent(
                             new CustomEvent("twyne:load-folio", {
                               detail: content,
                             }),
                           );
                         })}
                       >
                         <span class="dept-label block">
                           Folio{" "}
                           {[
                             "I",
                             "II",
                             "III",
                             "IV",
                             "V",
                             "VI",
                             "VII",
                             "VIII",
                             "IX",
                             "X",
                           ][idx] ?? idx + 1}
                         </span>
                         {folio.name}
                       </button>
                     );
                   })}
                   {store.newFolioFormOpen ? (
                     <div class="space-y-2">
                       <input
                         id="new-folio-name"
                         autoFocus
                         placeholder="Folio name"
                         class="w-full border border-[var(--color-paper-3)] bg-[var(--color-paper-soft)] px-3 py-2 text-sm text-[var(--color-ink)] placeholder:text-[var(--color-ink-muted)] focus:border-[var(--color-vermilion)] focus:outline-none"
                         style="font-family: var(--font-display); border-radius: 2px;"
                         onKeyDown$={(e) => {
                           if (e.key === "Enter") {
                             const input = e.target as HTMLInputElement;
                             const name = input.value.trim() || "Untitled folio";
                             const newFolio: Folio = {
                               id: crypto.randomUUID(),
                               name,
                               type: "notes",
                               createdAt: Date.now(),
                               updatedAt: Date.now(),
                             };
                             store.folios = [...store.folios, newFolio];
                             store.activeFolioId = newFolio.id;
                             store.editorSeed = "";
                             store.folioKey += 1;
                             store.newFolioFormOpen = false;
                             void saveFoliosToIdb(store.folios);
                             void saveFolioContentToIdb(newFolio.id, "");
                             void saveActiveFolioIdToIdb(newFolio.id);
                           }
                           if (e.key === "Escape") {
                             store.newFolioFormOpen = false;
                           }
                         }}
                       />
                       <div class="flex gap-2">
                         <button
                           onClick$={$(() => {
                             const input = document.getElementById(
                               "new-folio-name",
                             ) as HTMLInputElement | null;
                             const name =
                               input?.value.trim() || "Untitled folio";
                             const newFolio: Folio = {
                               id: crypto.randomUUID(),
                               name,
                               type: "notes",
                               createdAt: Date.now(),
                               updatedAt: Date.now(),
                             };
                             store.folios = [...store.folios, newFolio];
                             store.activeFolioId = newFolio.id;
                             store.editorSeed = "";
                             store.folioKey += 1;
                             store.newFolioFormOpen = false;
                             void saveFoliosToIdb(store.folios);
                             void saveFolioContentToIdb(newFolio.id, "");
                             void saveActiveFolioIdToIdb(newFolio.id);
                           })}
                           class="btn-press flex-1 text-xs"
                         >
                           Create
                         </button>
                         <button
                           onClick$={$(() => {
                             store.newFolioFormOpen = false;
                           })}
                           class="btn-paper flex-1 text-xs"
                         >
                           Cancel
                         </button>
                       </div>
                     </div>
                   ) : (
                     <button
                       class="w-full text-left px-3 py-2 border border-dashed border-[var(--color-paper-3)] text-sm text-[var(--color-ink-muted)] hover:text-[var(--color-ink)] hover:bg-[var(--color-paper-soft)] focus-ring"
                       style="font-family: var(--font-serif); border-radius: 2px;"
                       onClick$={$(() => {
                         store.newFolioFormOpen = true;
                       })}
                     >
                       <span class="dept-label block">+</span>
                       New folio
                     </button>
                   )}
                 </div>

                 <div
                   class="ornament-divider"
                   style="font-family: var(--font-display);"
                 >
                   ❦
                 </div>

                 <Link
                   href="/personas"
                   class="w-full text-left px-3 py-2.5 text-sm border border-transparent text-[var(--color-ink-light)] hover:bg-[var(--color-paper-soft)] hover:text-[var(--color-ink)] focus-ring"
                   style="font-family: var(--font-display); border-radius: 2px;"
                 >
                   <span class="dept-label block">Room of Editors</span>
                   Manage editorial staff
                 </Link>

                 <Link
                   href="/library"
                   class="w-full text-left px-3 py-2.5 text-sm border border-transparent text-[var(--color-ink-light)] hover:bg-[var(--color-paper-soft)] hover:text-[var(--color-ink)] focus-ring"
                   style="font-family: var(--font-display); border-radius: 2px;"
                 >
                   <span class="dept-label block">The Library</span>
                   All documents
                 </Link>

                 <Link
                   href="/rubric"
                   class="w-full text-left px-3 py-2.5 text-sm border border-transparent text-[var(--color-ink-light)] hover:bg-[var(--color-paper-soft)] hover:text-[var(--color-ink)] focus-ring"
                   style="font-family: var(--font-display); border-radius: 2px;"
                 >
                   <span class="dept-label block">Galley Proof</span>
                   Full rubric report
                 </Link>

+                <Link
+                  href="/apparatus"
+                  class="w-full text-left px-3 py-2.5 text-sm border border-transparent text-[var(--color-ink-light)] hover:bg-[var(--color-paper-soft)] hover:text-[var(--color-ink)] focus-ring"
+                  style="font-family: var(--font-display); border-radius: 2px;"
+                >
+                  <span class="dept-label block">The Apparatus</span>
+                  Research + bibliography
+                </Link>
+
                 <div
                   class="ornament-divider"
                   style="font-family: var(--font-display);"
                 >
                   ❦
                 </div>

                 {store.confirmNukeOpen ? (
                   <div class="index-card p-3 space-y-2">
                     <p
                       class="text-xs text-[var(--color-ink-light)]"
                       style="font-family: var(--font-serif);"
                     >
                       Start a brand new piece? Your current draft and dossier
                       will be replaced.
                     </p>
                     <div class="flex gap-2">
                       <button
                         onClick$={$(() => {
                           void clearIdbStore();
                           store.brief = null;
                           store.folios = [];
                           store.activeFolioId = null;
                           store.editorSeed = "";
                           store.confirmNukeOpen = false;
                           store.mode = "onboarding";
                         })}
                         class="btn-press flex-1 text-xs"
                       >
                         Replace
                       </button>
                       <button
                         onClick$={$(() => {
                           store.confirmNukeOpen = false;
                         })}
                         class="btn-paper flex-1 text-xs"
                       >
                         Cancel
                       </button>
                     </div>
                   </div>
                 ) : (
                   <button
                     onClick$={$(() => {
                       store.confirmNukeOpen = true;
                     })}
                     class="btn-press w-full"
                   >
                     + File a new piece
                   </button>
                 )}
               </div>
             </div>
           </aside>

           {/* ── Main area ─────────────────────────────────────── */}
           <div class="flex-1 flex flex-col min-w-0">
             {/* Masthead */}
