                                style="font-family: var(--font-typewriter); letter-spacing: 0.12em;"
                              >
                                Clear
                              </button>
                            </>
                          )}

                          {!store.existingMaterial && (
                            <span
                              class="text-xs text-[var(--color-ink-muted)] italic"
