                              : "var(--color-paper-3)",
                        }}
                      />
                    ))}
                  </div>

                  <button onClick$={goNext} class="btn-press" disabled={store.submitting}>
                    {store.submitting ? "Sending…" : store.step === STEPS.length - 1 ? "Send to press" : "Next"}
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
